const body = $json.body || $json;
const candidates = body.candidates || [];
const filters = body.filters || {};
const compact = candidates.map((item, index) => ({
  index,
  numbers: item.numbers,
  score: item.score,
  sum: item.sum,
  even_count: item.even_count,
}));
const prompt = `Voce e um analista de loterias. Reordene os candidatos abaixo do melhor para o pior com foco em distribuicao, equilibrio, soma, paridade e coerencia estatistica. Responda apenas JSON com: recommended_order, confidence, notes.\n\nFiltros: ${JSON.stringify(filters)}\n\nCandidatos: ${JSON.stringify(compact)}`;
return [{ json: { filters, candidates: compact, prompt } }];

function safeParse(value) {
  if (!value) return null;
  if (typeof value === 'object') return value;
  try { return JSON.parse(value); } catch (_) { return null; }
}

const left = $input.item.json;
const openaiRaw = left?.message?.content || left?.choices?.[0]?.message?.content || left?.output_text || left;
const geminiRaw = $input.item.json_1?.candidates?.[0]?.content?.parts?.[0]?.text || $input.item.json_1;
const openai = safeParse(openaiRaw) || {};
const gemini = safeParse(geminiRaw) || {};

const openaiOrder = Array.isArray(openai.recommended_order) ? openai.recommended_order : [];
const geminiOrder = Array.isArray(gemini.recommended_order) ? gemini.recommended_order : [];
const source = openaiOrder.length ? openaiOrder : geminiOrder;
const sameTop = openaiOrder[0] !== undefined && openaiOrder[0] === geminiOrder[0];
const confidence = sameTop ? 0.82 : 0.61;

return [{ json: {
  recommended_order: source,
  confidence,
  notes: sameTop ? 'ChatGPT e Gemini concordaram no topo do ranking.' : 'Ranking retornado com consenso parcial.',
  provider_votes: {
    chatgpt: openai.notes || 'sem notas',
    gemini: gemini.notes || 'sem notas'
  }
} }];
